import React, { useEffect, useState } from 'react';
import axios from 'axios';

function CareTipDetail({ id, onBack }) {
  const [tip, setTip] = useState(null);

  useEffect(() => {
    const fetchTip = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/caretips/${id}`);
        setTip(res.data);
        console.log(res.data); 
      } catch {
        alert('Failed to load care tip');
      }
    };
    fetchTip();
  }, [id]);

  if (!tip) return <div>Loading...</div>;

  return (
    <div>
      <div>
      <button onClick={onBack}>← Back to Care Tips</button>
      <h2>{tip.plantName} - {tip.topic}</h2>
      <p>{tip.tip}</p>
    </div>

      <img
        src={tip.thumbnailUrl || '/default.jpg'}
        alt={tip.title}
        style={{ width: '100%', maxHeight: '300px', objectFit: 'cover' }}
        onError={(e) => { e.target.src = '/default.jpg'; }}
      />

      <p>{tip.content}</p>

      {tip.videoUrl && (
        <div style={{ marginTop: '20px' }}>
          <h4>Watch Video</h4>
          <iframe
            width="100%"
            height="315"
            src={tip.videoUrl}
            title="Care Tip Video"
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />
        </div>
      )}
    </div>
  );
}

export default CareTipDetail;
